    public void handleTrades(Client client, Object message)
    {
        //
        //     {
        //         "topic": "publicTrade.BTCUSDT",
        //         "type": "snapshot",
        //         "ts": 1672304486868,
        //         "data": [
        //             {
        //                 "T": 1672304486865,
        //                 "s": "BTCUSDT",
        //                 "S": "Buy",
        //                 "v": "0.001",
        //                 "p": "16578.50",
        //                 "L": "PlusTick",
        //                 "i": "20f43950-d8dd-5b31-9112-a178eb6023af",
        //                 "BT": false
        //             }
        //         ]
        //     }
        //
        Object data = this.safeValue(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object topic = this.safeString(message, "topic", "");
        Object trades = data;
        Object parts = Helpers.split(topic, ".");
        Object isSpot = Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(client.url, "spot"), 0);
        Object marketType = ((Helpers.isTrue((isSpot)))) ? "spot" : "contract";
        Object marketId = this.safeString(parts, 1);
        Object market = this.safeMarket(marketId, null, null, marketType);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object stored = this.safeValue(this.trades, symbol);
        if (Helpers.isTrue(Helpers.isEqual(stored, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            stored = new ArrayCache(((Number)limit).intValue());
            Helpers.addElementToObject(this.trades, symbol, stored);
        }
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(trades)); j++)
        {
            Object parsed = this.parseWsTrade(Helpers.GetValue(trades, j), market);
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
        }
        Object messageHash = Helpers.add(Helpers.add("trade", ":"), symbol);
        client.resolve(stored, messageHash);
    }

    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        // public
        //    {
        //         "T": 1672304486865,
        //         "s": "BTCUSDT",
        //         "S": "Buy",
        //         "v": "0.001",
        //         "p": "16578.50",
        //         "L": "PlusTick",
        //         "i": "20f43950-d8dd-5b31-9112-a178eb6023af",
        //         "BT": false
        //     }
        //
        // spot private
        //     {
        //         "e": "ticketInfo",
        //         "E": "1662348310386",
        //         "s": "BTCUSDT",
        //         "q": "0.001007",
        //         "t": "1662348310373",
        //         "p": "19842.02",
        //         "T": "2100000000002220938",
        //         "o": "1238261807653647872",
        //         "c": "spotx008",
        //         "O": "1238225004531834368",
        //         "a": "533287",
        //         "A": "642908",
        //         "m": false,
        //         "S": "BUY"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("i", "T", "v")));
        Object isContract = (Helpers.inOp(trade, "BT"));
        Object marketType = ((Helpers.isTrue(isContract))) ? "contract" : "spot";
        if (Helpers.isTrue(!Helpers.isEqual(market, null)))
        {
            marketType = Helpers.GetValue(market, "type");
        }
        Object marketId = this.safeString(trade, "s");
        market = this.safeMarket(marketId, market, null, marketType);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger2(trade, "t", "T");
        Object side = this.safeStringLower(trade, "S");
        Object takerOrMaker = null;
        Object m = this.safeValue(trade, "m");
        if (Helpers.isTrue(Helpers.isEqual(side, null)))
        {
            side = ((Helpers.isTrue(m))) ? "buy" : "sell";
        } else
        {
            // spot private
            takerOrMaker = m;
        }
        Object price = this.safeString(trade, "p");
        Object amount = this.safeString2(trade, "q", "v");
        Object orderId = this.safeString(trade, "o");
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", BybitCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "order", orderId );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", price );
            put( "amount", amount );
            put( "cost", null );
            put( "fee", null );
        }}, market);
    }

    public Object getPrivateType(Object url)
    {
        if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(url, "spot"), 0)))
        {
            return "spot";
        } else if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(url, "v5/private"), 0)))
        {
            return "unified";
        } else
        {
            return "usdc";
        }
    }

    /**
     * @method
     * @name bybit#watchMyTrades
     * @description watches information on multiple trades made by the user
     * @see https://bybit-exchange.github.io/docs/v5/websocket/private/execution
     * @see https://bybit-exchange.github.io/docs/v5/websocket/private/fast-execution
     * @param {string} symbol unified market symbol of the market orders were made in
     * @param {int} [since] the earliest time in ms to fetch orders for
     * @param {int} [limit] the maximum number of order structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.unifiedMargin] use unified margin account
     * @param {boolean} [params.executionFast] use fast execution
     * @returns {object[]} a list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            Object method = "watchMyTrades";
            Object messageHash = "myTrades";
            (this.loadMarkets()).join();
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                symbol = this.symbol(symbol);
                messageHash = Helpers.add(messageHash, Helpers.add(":", symbol));
            }
            Object url = (this.getUrlByMarketType(symbol, true, method, parameters)).join();
            (this.authenticate(url)).join();
            Object topicByMarket = new java.util.HashMap<String, Object>() {{
                put( "spot", "ticketInfo" );
                put( "unified", "execution" );
                put( "usdc", "user.openapi.perp.trade" );
            }};
            Object topic = this.safeValue(topicByMarket, this.getPrivateType(url));
            Object executionFast = false;
            var executionFastparametersVariable = this.handleOptionAndParams(parameters, "watchMyTrades", "executionFast", false);
            executionFast = ((java.util.List<Object>) executionFastparametersVariable).get(0);
            parameters = ((java.util.List<Object>) executionFastparametersVariable).get(1);
            if (Helpers.isTrue(executionFast))
            {
                topic = "execution.fast";
            }
            Object trades = (this.watchTopics(url, new java.util.ArrayList<Object>(java.util.Arrays.asList(messageHash)), new java.util.ArrayList<Object>(java.util.Arrays.asList(topic)), parameters)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(trades, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySymbolSinceLimit(trades, symbol, since, limit, true);
        });

    }

