    public void handleMyTrades(Client client, Object message)
    {
        //
        // spot
        //    {
        //        "type": "snapshot",
        //        "topic": "ticketInfo",
        //        "ts": "1662348310388",
        //        "data": [
        //            {
        //                "e": "ticketInfo",
        //                "E": "1662348310386",
        //                "s": "BTCUSDT",
        //                "q": "0.001007",
        //                "t": "1662348310373",
        //                "p": "19842.02",
        //                "T": "2100000000002220938",
        //                "o": "1238261807653647872",
        //                "c": "spotx008",
        //                "O": "1238225004531834368",
        //                "a": "533287",
        //                "A": "642908",
        //                "m": false,
        //                "S": "BUY"
        //            }
        //        ]
        //    }
        // unified
        //     {
        //         "id": "592324803b2785-26fa-4214-9963-bdd4727f07be",
        //         "topic": "execution",
        //         "creationTime": 1672364174455,
        //         "data": [
        //             {
        //                 "category": "linear",
        //                 "symbol": "XRPUSDT",
        //                 "execFee": "0.005061",
        //                 "execId": "7e2ae69c-4edf-5800-a352-893d52b446aa",
        //                 "execPrice": "0.3374",
        //                 "execQty": "25",
        //                 "execType": "Trade",
        //                 "execValue": "8.435",
        //                 "isMaker": false,
        //                 "feeRate": "0.0006",
        //                 "tradeIv": "",
        //                 "markIv": "",
        //                 "blockTradeId": "",
        //                 "markPrice": "0.3391",
        //                 "indexPrice": "",
        //                 "underlyingPrice": "",
        //                 "leavesQty": "0",
        //                 "orderId": "f6e324ff-99c2-4e89-9739-3086e47f9381",
        //                 "orderLinkId": "",
        //                 "orderPrice": "0.3207",
        //                 "orderQty": "25",
        //                 "orderType": "Market",
        //                 "stopOrderType": "UNKNOWN",
        //                 "side": "Sell",
        //                 "execTime": "1672364174443",
        //                 "isLeverage": "0"
        //             }
        //         ]
        //     }
        //
        // execution.fast
        //
        //     {
        //         "topic": "execution.fast",
        //         "creationTime": 1757405601981,
        //         "data": [
        //             {
        //                 "category": "linear",
        //                 "symbol": "BTCUSDT",
        //                 "execId": "ffcac6ac-7571-536d-a28a-847dd7d08a0f",
        //                 "execPrice": "112529.6",
        //                 "execQty": "0.001",
        //                 "orderId": "6e25ab73-7a55-4ae7-adc2-8ea95f167c85",
        //                 "isMaker": false,
        //                 "orderLinkId": "test-00001",
        //                 "side": "Buy",
        //                 "execTime": "1757405601977",
        //                 "seq": 9515624038
        //             }
        //         ]
        //     }
        //
        Object topic = this.safeString(message, "topic", "");
        Object spot = Helpers.isEqual(topic, "ticketInfo");
        Object executionFast = Helpers.isEqual(topic, "execution.fast");
        Object data = this.safeValue(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        if (!Helpers.isTrue(Helpers.isArray(data)))
        {
            data = this.safeValue(data, "result", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        }
        if (Helpers.isTrue(Helpers.isEqual(this.myTrades, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            this.myTrades = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
        }
        Object trades = this.myTrades;
        Object symbols = new java.util.HashMap<String, Object>() {{}};
        Object filterExecTypes = this.handleOption("watchMyTrades", "filterExecTypes", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object rawTrade = Helpers.GetValue(data, i);
            Object parsed = null;
            if (Helpers.isTrue(Helpers.isTrue(spot) && !Helpers.isTrue(executionFast)))
            {
                parsed = this.parseWsTrade(rawTrade);
            } else
            {
                // filter unified trades
                Object execType = this.safeString(rawTrade, "execType", "");
                if (Helpers.isTrue(executionFast))
                {
                    execType = "Trade";
                }
                if (!Helpers.isTrue(this.inArray(execType, filterExecTypes)))
                {
                    continue;
                }
                parsed = this.parseTrade(rawTrade);
            }
            Object symbol = Helpers.GetValue(parsed, "symbol");
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                continue;
            }
            Helpers.addElementToObject(symbols, symbol, true);
            Helpers.callDynamically(trades, "append", new Object[]{parsed});
        }
        Object keys = Helpers.objectKeys(symbols);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
        {
            Object currentMessageHash = Helpers.add("myTrades:", Helpers.GetValue(keys, i));
            client.resolve(trades, currentMessageHash);
        }
        // non-symbol specific
        Object messageHash = "myTrades";
        client.resolve(trades, messageHash);
    }

    /**
     * @method
     * @name bybit#watchPositions
     * @see https://bybit-exchange.github.io/docs/v5/websocket/private/position
     * @description watch all open positions
     * @param {string[]} [symbols] list of unified market symbols
     * @param {int} [since] the earliest time in ms to fetch positions for
     * @param {int} [limit] the maximum number of positions to retrieve
     * @param {object} params extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [position structure]{@link https://docs.ccxt.com/en/latest/manual.html#position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchPositions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object method = "watchPositions";
            Object messageHash = "";
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(symbols, null))) && !Helpers.isTrue(this.isEmpty(symbols))))
            {
                symbols = this.marketSymbols(symbols);
                messageHash = Helpers.add("::", String.join((String)",", (java.util.List<String>)symbols));
            }
            Object firstSymbol = this.safeString(symbols, 0);
            Object url = (this.getUrlByMarketType(firstSymbol, true, method, parameters)).join();
            messageHash = Helpers.add("positions", messageHash);
            Client client = this.client(url);
            (this.authenticate(url)).join();
            this.setPositionsCache(client, symbols);
            Object cache = this.positions;
            Object fetchPositionsSnapshot = this.handleOption("watchPositions", "fetchPositionsSnapshot", true);
            Object awaitPositionsSnapshot = this.handleOption("watchPositions", "awaitPositionsSnapshot", true);
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(fetchPositionsSnapshot) && Helpers.isTrue(awaitPositionsSnapshot)) && Helpers.isTrue(Helpers.isEqual(cache, null))))
            {
                Object snapshot = client.future("fetchPositionsSnapshot").getFuture().join();
                return this.filterBySymbolsSinceLimit(snapshot, symbols, since, limit, true);
            }
            Object topics = new java.util.ArrayList<Object>(java.util.Arrays.asList("position"));
            Object newPositions = (this.watchTopics(url, new java.util.ArrayList<Object>(java.util.Arrays.asList(messageHash)), topics, parameters)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                return newPositions;
            }
            return this.filterBySymbolsSinceLimit(cache, symbols, since, limit, true);
        });

    }

    public void setPositionsCache(Client client, Object... optionalArgs)
    {
        Object symbols = Helpers.getArg(optionalArgs, 0, null);
        if (Helpers.isTrue(!Helpers.isEqual(this.positions, null)))
        {
            return;
        }
        Object fetchPositionsSnapshot = this.handleOption("watchPositions", "fetchPositionsSnapshot", true);
        if (Helpers.isTrue(fetchPositionsSnapshot))
        {
            Object messageHash = "fetchPositionsSnapshot";
            if (!Helpers.isTrue((Helpers.inOp(client.futures, messageHash))))
            {
                client.future((String)messageHash);
                this.spawn(() -> { try { this.loadPositionsSnapshot(client, messageHash); } catch(Exception _e) { throw new RuntimeException(_e); } });
            }
        } else
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
        }
    }

    public java.util.concurrent.CompletableFuture<Object> loadPositionsSnapshot(Client client, Object messageHash2)
    {
        final Object messageHash3 = messageHash2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object messageHash = messageHash3;
            // as only one ws channel gives positions for all types, for snapshot must load all positions
            Object fetchFunctions = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.fetchPositions(null, (Object) new java.util.HashMap<String, Object>() {{
        put( "type", "swap" );
        put( "subType", "linear" );
    }}), this.fetchPositions(null, (Object) new java.util.HashMap<String, Object>() {{
        put( "type", "swap" );
        put( "subType", "inverse" );
    }})));
            Object promises = (Helpers.promiseAll(fetchFunctions)).join();
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
            Object cache = this.positions;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(promises)); i++)
            {
                Object positions = Helpers.GetValue(promises, i);
                for (var ii = 0; Helpers.isLessThan(ii, Helpers.getArrayLength(positions)); ii++)
                {
                    Object position = Helpers.GetValue(positions, ii);
                    Helpers.callDynamically(cache, "append", new Object[]{position});
                }
            }
            // don't remove the future from the .futures cache
            if (Helpers.isTrue(Helpers.inOp(client.futures, messageHash)))
            {
                io.github.ccxt.ws.Future future = (io.github.ccxt.ws.Future)Helpers.GetValue(client.futures, messageHash);
                ((io.github.ccxt.ws.Future)future).resolve(cache);
                client.resolve(cache, "position");
            }
            return null;
        });

    }

    public void handlePositions(Client client, Object message)
    {
        //
        //    {
        //        topic: 'position',
        //        id: '504b2671629b08e3c4f6960382a59363:3bc4028023786545:0:01',
        //        creationTime: 1694566055295,
        //        data: [{
        //            bustPrice: '15.00',
        //            category: 'inverse',
        //            createdTime: '1670083436351',
        //            cumRealisedPnl: '0.00011988',
        //            entryPrice: '19358.58553268',
        //            leverage: '10',
        //            liqPrice: '15.00',
        //            markPrice: '25924.00',
        //            positionBalance: '0.0000156',
        //            positionIdx: 0,
        //            positionMM: '0.001',
        //            positionIM: '0.0000015497',
        //            positionStatus: 'Normal',
        //            positionValue: '0.00015497',
        //            riskId: 1,
        //            riskLimitValue: '150',
        //            side: 'Buy',
        //            size: '3',
        //            stopLoss: '0.00',
        //            symbol: 'BTCUSD',
        //            takeProfit: '0.00',
        //            tpslMode: 'Full',
        //            tradeMode: 0,
        //            autoAddMargin: 1,
        //            trailingStop: '0.00',
        //            unrealisedPnl: '0.00003925',
        //            updatedTime: '1694566055293',
        //            adlRankIndicator: 3
        //        }]
        //    }
        //
        // each account is connected to a different endpoint
        // and has exactly one subscriptionhash which is the account type
        if (Helpers.isTrue(Helpers.isEqual(this.positions, null)))
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
        }
        Object cache = this.positions;
        Object newPositions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object rawPositions = this.safeValue(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawPositions)); i++)
        {
            Object rawPosition = Helpers.GetValue(rawPositions, i);
            Object position = this.parsePosition(rawPosition);
            Object side = this.safeString(position, "side");
            // hacky solution to handle closing positions
            // without crashing, we should handle this properly later
            ((java.util.List<Object>)newPositions).add(position);
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(side, null)) || Helpers.isTrue(Helpers.isEqual(side, ""))))
            {
                // closing update, adding both sides to "reset" both sides
                // since we don't know which side is being closed
                Helpers.addElementToObject(position, "side", "long");
                Helpers.callDynamically(cache, "append", new Object[]{position});
                Helpers.addElementToObject(position, "side", "short");
                Helpers.callDynamically(cache, "append", new Object[]{position});
                Helpers.addElementToObject(position, "side", null);
            } else
            {
                // regular update
                Helpers.callDynamically(cache, "append", new Object[]{position});
            }
        }
        Object messageHashes = this.findMessageHashes(client, "positions::");
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messageHashes)); i++)
        {
            Object messageHash = Helpers.GetValue(messageHashes, i);
            Object parts = Helpers.split(messageHash, "::");
            Object symbolsString = Helpers.GetValue(parts, 1);
            Object symbols = Helpers.split(symbolsString, ",");
            Object positions = this.filterByArray(newPositions, "symbol", symbols, false);
            if (!Helpers.isTrue(this.isEmpty(positions)))
            {
                client.resolve(positions, messageHash);
            }
        }
        client.resolve(newPositions, "positions");
    }

